import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, Pagination, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { AttendanceRecordDto, DepartmentDto } from '../../../services/ns/models';
import { formatDateLocal, formatTime } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const PAGE_SIZE = 50;

const ChamCongPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);

  const [fromDate, setFromDate] = useState(monthStart);
  const [toDate, setToDate] = useState(monthEnd);
  const [departmentId, setDepartmentId] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [depts, setDepts] = useState<DepartmentDto[]>([]);
  const [items, setItems] = useState<AttendanceRecordDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [syncConfirm, setSyncConfirm] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService.getDepartments().then(d => { if (!cancelled) setDepts(d); }).catch(() => {});
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService.getAttendance({
        fromDate,
        toDate,
        departmentId: departmentId || undefined,
        page: currentPage,
        pageSize: PAGE_SIZE,
      })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải chấm công', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fromDate, toDate, departmentId, currentPage, reloadKey]);

  const lateCount = items.filter(r => r.isLate).length;

  const handleSync = async () => {
    setSyncing(true);
    try {
      await hrService.syncAttendance();
      dispatch(addToast({ message: 'Đồng bộ máy chấm công thành công', type: 'success' }));
      setSyncConfirm(false);
      setCurrentPage(p => p);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Đồng bộ thất bại', type: 'error' }));
    } finally {
      setSyncing(false);
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-clock" /> Chấm công</h1>
          <p className={styles.subtitle}>Đi trễ: {lateCount} · Tổng bản ghi: {totalCount}</p>
        </div>
        <div className={styles.headerActions}>
          {syncConfirm ? (
            <>
              <Button variant="primary" onClick={handleSync} disabled={syncing}>Xác nhận đồng bộ</Button>
              <Button variant="secondary" onClick={() => setSyncConfirm(false)}>Huỷ</Button>
            </>
          ) : (
            <Button variant="secondary" onClick={() => setSyncConfirm(true)}>
              <i className="fas fa-sync" /> Đồng bộ máy CC
            </Button>
          )}
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-cham-cong-filters`}>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate ?? ''); setToDate(v.toDate ?? ''); setCurrentPage(1); }}
        />
        <Select
          value={departmentId}
          onChange={e => { setDepartmentId(e.target.value); setCurrentPage(1); }}
          options={[
            { value: '', label: 'Tất cả phòng ban' },
            ...depts.map(d => ({ value: d.id, label: d.name })),
          ]}
          size="small"
        />
        <ListSearchRefreshButtons testIdPrefix="erp-cham-cong" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu chấm công</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Ngày</th>
                  <th>Họ tên</th>
                  <th>Vào</th>
                  <th>Ra</th>
                  <th className={styles.colRight}>Tăng ca (h)</th>
                  <th>TT</th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id} className={r.isLate ? styles.rowDanger : undefined}>
                    <td>{formatDateLocal(r.attendanceDate)}</td>
                    <td>{r.employeeName}</td>
                    <td>{formatTime(r.checkIn)}</td>
                    <td>{formatTime(r.checkOut)}</td>
                    <td className={styles.colRight}>{r.overtimeHours > 0 ? r.overtimeHours.toFixed(1) : '—'}</td>
                    <td>
                      <span className={r.isLate ? styles.tagWarning : styles.tagSuccess}>
                        {r.isLate ? 'Đi trễ' : 'Đúng giờ'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {totalCount > PAGE_SIZE && (
          <div className={styles.paginationRow}>
            <Pagination
              currentPage={currentPage}
              totalPages={Math.ceil(totalCount / PAGE_SIZE)}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={setCurrentPage}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default ChamCongPage;
